// BucketServiceServer is the server API for BucketService service.
// All implementations must embed UnimplementedBucketServiceServer
// for forward compatibility.
//
// BucketService provides ledger operations
type BucketServiceServer interface {
	// ListLedgers streams all ledgers info in the cluster
	ListLedgers(*ListLedgersRequest, grpc.ServerStreamingServer[commonpb.LedgerInfo]) error
	// GetLedger returns a ledger info by its name or ID
	GetLedger(context.Context, *GetLedgerRequest) (*commonpb.LedgerInfo, error)
	// GetAccount retrieves an account by address
	GetAccount(context.Context, *GetAccountRequest) (*commonpb.Account, error)
	// GetTransaction retrieves a transaction by ID
	GetTransaction(context.Context, *GetTransactionRequest) (*GetTransactionResponse, error)
	// ListTransactions streams all transactions for a ledger (newest first)
	ListTransactions(*ListTransactionsRequest, grpc.ServerStreamingServer[commonpb.Transaction]) error
	// ListAccounts streams all accounts for a ledger (alphabetical order)
	ListAccounts(*ListAccountsRequest, grpc.ServerStreamingServer[commonpb.Account]) error
	// Apply applies actions (create/delete ledger, create transaction, revert, save/delete metadata)
	Apply(context.Context, *ApplyRequest) (*ApplyResponse, error)
	// GetPrimaryMetrics returns metrics from the primary Pebble store. Supports node_id targeting.
	GetPrimaryMetrics(context.Context, *GetPrimaryMetricsRequest) (*GetPrimaryMetricsResponse, error)
	// GetSecondaryMetrics returns metrics from the secondary (read index) Pebble store. Supports node_id targeting.
	GetSecondaryMetrics(context.Context, *GetSecondaryMetricsRequest) (*GetSecondaryMetricsResponse, error)
	// CheckStore verifies store integrity (hash chain and derived data consistency)
	CheckStore(*CheckStoreRequest, grpc.ServerStreamingServer[CheckStoreEvent]) error
	// ListAuditEntries streams audit trail entries (success and failure)
	ListAuditEntries(*ListAuditEntriesRequest, grpc.ServerStreamingServer[auditpb.AuditEntry]) error
	// GetAuditEntry returns a single audit entry by sequence number
	GetAuditEntry(context.Context, *GetAuditEntryRequest) (*auditpb.AuditEntry, error)
	// GetEventsSinks returns the current per-sink configurations and statuses
	GetEventsSinks(context.Context, *GetEventsSinksRequest) (*GetEventsSinksResponse, error)
	// ListPeriods streams all periods
	ListPeriods(*ListPeriodsRequest, grpc.ServerStreamingServer[commonpb.Period]) error
	// ListLogs streams system logs; when ledger is set, streams only logs for that ledger
	ListLogs(*ListLogsRequest, grpc.ServerStreamingServer[commonpb.Log]) error
	// GetLog returns a single system log by sequence number
	GetLog(context.Context, *GetLogRequest) (*commonpb.Log, error)
	// GetPeriodSchedule returns the current automatic period rotation schedule
	GetPeriodSchedule(context.Context, *GetPeriodScheduleRequest) (*GetPeriodScheduleResponse, error)
	// ListSigningKeys streams all registered signing keys
	ListSigningKeys(*ListSigningKeysRequest, grpc.ServerStreamingServer[commonpb.SigningKey]) error
	// Discovery returns server capabilities and configuration for clients
	Discovery(context.Context, *DiscoveryRequest) (*DiscoveryResponse, error)
	// GetMetadataSchemaStatus returns the conversion status for all declared metadata fields
	GetMetadataSchemaStatus(context.Context, *GetMetadataSchemaStatusRequest) (*GetMetadataSchemaStatusResponse, error)
	// AnalyzeAccounts scans all accounts in a ledger and suggests a Chart of Accounts
	AnalyzeAccounts(*AnalyzeAccountsRequest, grpc.ServerStreamingServer[AnalyzeAccountsEvent]) error
	// AnalyzeTransactions scans all transactions in a ledger and discovers flow patterns
	AnalyzeTransactions(*AnalyzeTransactionsRequest, grpc.ServerStreamingServer[AnalyzeTransactionsEvent]) error
	// CreatePreparedQuery creates a named prepared query for a ledger
	CreatePreparedQuery(context.Context, *CreatePreparedQueryRequest) (*CreatePreparedQueryResponse, error)
	// UpdatePreparedQuery updates the filter of an existing prepared query
	UpdatePreparedQuery(context.Context, *UpdatePreparedQueryRequest) (*UpdatePreparedQueryResponse, error)
	// DeletePreparedQuery removes a prepared query
	DeletePreparedQuery(context.Context, *DeletePreparedQueryRequest) (*DeletePreparedQueryResponse, error)
	// ListPreparedQueries lists all prepared queries for a ledger
	ListPreparedQueries(context.Context, *ListPreparedQueriesRequest) (*ListPreparedQueriesResponse, error)
	// ExecutePreparedQuery executes a prepared query against the read index store
	ExecutePreparedQuery(context.Context, *ExecutePreparedQueryRequest) (*ExecutePreparedQueryResponse, error)
	// GetIndexStatus returns the current state of the read index builder
	GetIndexStatus(context.Context, *GetIndexStatusRequest) (*GetIndexStatusResponse, error)
	// GetLedgerStats returns aggregate statistics for a ledger
	GetLedgerStats(context.Context, *GetLedgerStatsRequest) (*commonpb.LedgerStats, error)
	// AggregateVolumes returns per-asset aggregated volumes for filtered accounts
	AggregateVolumes(context.Context, *AggregateVolumesRequest) (*commonpb.AggregateResult, error)
	// GetNumscript returns a numscript by name and optional version
	GetNumscript(context.Context, *GetNumscriptRequest) (*commonpb.NumscriptInfo, error)
	// ListNumscripts streams all numscripts (latest version of each)
	ListNumscripts(*ListNumscriptsRequest, grpc.ServerStreamingServer[commonpb.NumscriptInfo]) error
	// InspectIndex scans a metadata index and returns distinct values, facets, or a summary
	InspectIndex(context.Context, *InspectIndexRequest) (*InspectIndexResponse, error)
	// Barrier proposes a no-op through Raft consensus. When it returns, all
	// previously proposed entries are guaranteed to have been applied to the FSM.
	// Useful for ensuring read-after-write consistency across API calls.
	Barrier(context.Context, *BarrierRequest) (*BarrierResponse, error)
	mustEmbedUnimplementedBucketServiceServer()
}

